fn factorial(n: i64) -> i64
    pre n >= 0 and n <= 20
    post ret >= 1
= {
    let mut result: i64 = 1;
    let mut i: i64 = 2;
    while i <= n {
        set result = result * i;
        set i = i + 1
    };
    result
};

fn main() -> i64 = {
    let q: i64 = read_int();
    for _i in 0..q {
        let val: i64 = read_int();
        let _p = println(factorial(val))
    };
    0
};
